config.script:
draft = self.view.custom.editDraft or {"meta": None, "attributes": []}
meta = draft.get("meta") or {}
defId = meta.get("locationTypeDefinitionId")
if defId is None:
	self.view.custom.editDraft = {"meta": meta, "attributes": []}
	return
attrs = BlueRidge.Location.Location.buildAttributesForType(defId, None)
self.view.custom.editDraft = {"meta": meta, "attributes": attrs}
self.view.custom.dirty = True

messageHandlers.script:
idx = payload.get("index") if payload else None
val = payload.get("value") if payload else None
if idx is None:
	return
draft = self.view.custom.editDraft or {"meta": None, "attributes": []}
attrs = list(draft.get("attributes") or [])
if idx < 0 or idx >= len(attrs):
	return
row = dict(attrs[idx])
row["value"] = val if val is not None else ""
attrs[idx] = row
self.view.custom.editDraft = {"meta": draft.get("meta"), "attributes": attrs}
self.view.custom.dirty = True
